<template>
  <canvas ref="canvasEl" id="canvasEl"/>
</template>

<script>
import { ref } from '@vue/reactivity';
import * as THREE from '../../public/js/three';
import getSpherePositions from '../../public/js/createLatticeSphere';
import { vertexShader as basicVertexShader, fragmentShader as basicFragmentShader } from '../../public/js/basicShader';
import { vertexShader as blurVertexShader, fragmentShader as blurFragmentShader } from '../../public/js/blurShader';
import Stats from 'stats.js';

export default {
  name: 'BGTheme',
  setup() {
    const canvas = ref(null)
  },
  data: () => {
    return {
      then: 0,
      clearColor: 0x101028,
      fogColor: 0x000018,
      fogNear: 4,
      fogFar: 14,
      fov: 75,
      minRenderDistance: 0.3,
      maxRenderDistance: 15,
      timeRotation: 0,
      mouseRotX: 0,
      mouseRotY: 0,
      mouseX: 0,
      mouseY: 0,
      velocities: []
    }
  },
  created() {
    this.createStats();
  },
  mounted() {
    this.init();

    window.addEventListener('resize', this.onResize);
    window.addEventListener('mousemove', this.updateMousePosition);
  },
  unmounted() {
    window.removeEventListener('resize', this.onResize);
    window.removeEventListener('mousemove', this.onResize);
    this.unmounted = true;
  },
  methods: {
    init() {
      // setup renderer
      this.renderer = new THREE.WebGLRenderer({antialias:true, canvas: this.$refs.canvasEl});
      this.renderer.setSize(window.innerWidth, window.innerHeight);
      this.renderer.setClearColor(this.clearColor, 1);
      this.renderer.extensions.get( 'EXT_color_buffer_float' );

      this.setupScene();
      this.setupPost();

      this.animate(0);
    },
    setupScene() {
      // setup scene that contains all the spheres
      this.scene = new THREE.Scene();
      this.scene.fog = new THREE.Fog(this.fogColor, this.fogNear, this.fogFar);

      // setup camera
      this.camera = new THREE.PerspectiveCamera(
        this.fov,
        window.innerWidth / window.innerHeight,
        this.minRenderDistance,
        this.maxRenderDistance
        );
      this.camera.position.y = 0.1;
      this.camera.position.z = 4;


      this.setupRenderTarget();

      // create sphere of spheres
      const sphereSize = 10;
      const pointSize = 0.1;
      this.pointSphere = this.createPointSphere(sphereSize, pointSize, 500);
      this.pointSphere.translateY(sphereSize * 0.9);
      this.scene.add(this.pointSphere);
    },
    setupPost() {
      // setup scene that shows the result of the render target
      this.postScene = new THREE.Scene();
      this.postCamera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);
      const plane = new THREE.PlaneGeometry(2, 2);
      this.planeMat = new THREE.ShaderMaterial({
        glslVersion: THREE.GLSL3,
        uniforms: {
          tDepth : { value: null },
          tColor: { value: null },
          minRenderDistance: { value: this.minRenderDistance},
          maxRenderDistance: { value: this.maxRenderDistance}
        },
        vertexShader: blurVertexShader,
        fragmentShader: blurFragmentShader
      });
      const quad = new THREE.Mesh(plane, this.planeMat);
      this.postScene.add(quad);
    },
    animate(now) {
      if(!this.unmounted)
        requestAnimationFrame(this.animate);

      this.stats.begin();
      {
        now *= 0.001;
        const delta = now - this.then;
        this.then = now;

        this.pointSphere.setRotationFromQuaternion(this.getCurrentRotation(delta));

        // render scene with depthbuffer to target
        this.renderer.setRenderTarget(this.target);
        this.renderer.render(this.scene, this.camera);

        this.planeMat.uniforms.tDepth.value = this.target.depthTexture;
        this.planeMat.uniforms.tColor.value = this.target.texture;

        // render quad with the target as a texture
        this.renderer.setRenderTarget(null);
        this.renderer.render(this.postScene, this.postCamera)
      }
      this.stats.end();
    },
    onResize() {
				this.camera.aspect = window.innerWidth / window.innerHeight;
				this.camera.updateProjectionMatrix();
        const dpr = this.renderer.getPixelRatio();
        this.target.setSize(window.innerWidth * dpr, window.innerHeight * dpr);
				this.renderer.setSize(window.innerWidth, window.innerHeight);
    },
    createPointSphere(sphereSize = 1, pointSize = 0.04, numPoints = 80) {
      const positions = getSpherePositions(numPoints);
      const group = new THREE.Group();

      positions.forEach(el => {
        let pos = el.multiplyScalar(sphereSize);
        let pointGeometry = new THREE.SphereGeometry(pointSize);
        pointGeometry.translate(pos.x, pos.y, pos.z);

        group.add(this.createShaderMesh(pointGeometry, 0xffffff));

        this.velocities.push(new THREE.Vector3(0, 0, 0));
      });

      return group;
    },
    setupRenderTarget() {
      if(this.target) this.target.dispose();

      this.target = new THREE.WebGLRenderTarget(window.innerWidth, window.innerHeight);
      this.target.texture.format = THREE.RGBFormat;
      this.target.depthBuffer = true;
      this.target.depthTexture = new THREE.DepthTexture();
      this.target.depthTexture.format = THREE.DepthFormat;
      this.target.depthTexture.type = THREE.UnsignedShortType;
    },
    createBasicMesh(geometry, color = 0xffffff) {
      const material = new THREE.MeshBasicMaterial({ color });
      return new THREE.Mesh(geometry, material);
    },
    createDepthMesh(geometry, color = 0xffffff) {
      const material = new THREE.MeshDepthMaterial({ color });
      return new THREE.Mesh(geometry, material);
    },
    createShaderMesh(geometry, color = 0xffffff) {
      const material = new THREE.ShaderMaterial({
        glslVersion: THREE.GLSL3,
        uniforms: {
          color: { value: new THREE.Color(color)},
          minRenderDistance: { value: this.minRenderDistance},
          maxRenderDistance: { value: this.maxRenderDistance}
        },
        vertexShader: basicVertexShader,
        fragmentShader: basicFragmentShader
      });
      return new THREE.Mesh(geometry, material);
    },
    createStats() {
      this.stats = new Stats();
      this.stats.showPanel(0);
      // document.body.appendChild(this.stats.dom);
    },
    updateMousePosition(event) {
      this.mouseX = (event.pageX / window.innerWidth - 0.5) * 2;
      this.mouseY = (event.pageY / window.innerHeight - 0.5) * 2;
    },
    // unused, might remove
    resetMousePosition(event) {
      this.mouseX = 0;
      this.mouseY = 0;
    },
    getCurrentRotation(delta) {
      this.mouseRotX += (this.mouseY - this.mouseRotX) / 10;
      const mouseQuatX = new THREE.Quaternion();
      mouseQuatX.setFromAxisAngle(
        new THREE.Vector3(1, 0, 0),
        this.mouseRotX * Math.PI / 40
      );

      this.mouseRotY += (this.mouseX - this.mouseRotY) / 10;
      const mouseQuatY = new THREE.Quaternion();
      mouseQuatY.setFromAxisAngle(
        new THREE.Vector3(0, 1, 0),
        this.mouseRotY * Math.PI / 20
      );

      this.timeRotation = this.timeRotation + 0.2 * delta;
      const timeQuaternion = new THREE.Quaternion();
      timeQuaternion.setFromAxisAngle(new THREE.Vector3(1, 0, 0), -this.timeRotation);

      return mouseQuatX.multiply(mouseQuatY.multiply(timeQuaternion));
    }
  }
}

</script>

<style scoped>
#canvasEl {
  position: absolute;
  top: 0;
  left: 0;
  z-index: -1;
}
</style>